[Form]
// PAHA 2011-08-25, FWI Foundation - 46890 Text block management -->
public class FWFTextBlockTable extends FormRun
{
    FWFTextBlockModule      module;

    int                     selectedTab;
    int                     selectedDetailsTab;

    #define.CurrentVersion(2)
    #localmacro.CurrentList
        selectedTab,
        selectedDetailsTab
    #endmacro
}

public void close()
{
    selectedTab = TextEditTab.tab();
    selectedDetailsTab = DetailsTab.tab();

    xSysLastValue::saveLast(this);

    super();
}

public void init()
{
    Object callerForm;

    super();

    if (element.args())
    {
        if (element.args().parmEnumType() == enumnum(FWFTextBlockModule))
        {
            module = element.args().parmEnum();
        }
        else if (element.args().caller())
        {
            callerForm = element.args().caller() as FormRun;
            if (callerForm && formHasMethod(callerForm, 'Module'))
            {
                module = callerForm.module();
            }
            else
            {
                FWFTextBlockTable_ds.queryBuildDataSource().clearLinks();
                FWFTextBlockTable_ds.queryBuildDataSource().clearDynalinks();
            }
        }
        else
        {
            FWFTextBlockTable_ds.queryBuildDataSource().clearLinks();
            FWFTextBlockTable_ds.queryBuildDataSource().clearDynalinks();
        }
    }

    FWFTextBlockTable_ds.object(fieldNum(FWFTextBlockTable, CompanyId)).skip(true);
    if (module)
    {
        FWFTextBlockTable_ds.object(fieldNum(FWFTextBlockTable, Module)).skip(false);
        FWFTextBlockTable_ds.query().dataSourceTable(tableNum(FWFTextBlockTable)).addRange(fieldNum(FWFTextBlockTable, Module)).value(QueryValue(module));
    }
    else
    {
        FWFTextBlockTable_ds.object(fieldNum(FWFTextBlockTable, Module)).skip(true);
    }

    xSysLastValue::getLast(this);

    TextEditTab.tab(selectedTab);

    this.updateDesign(InventDimFormDesignUpdate::Init);
}

void initParmDefault()
{
    selectedTab = 1;

    this.initDetailsTabFromModule();
}

void initDetailsTabFromModule()
{
    switch (module)
    {
        case FWFTextBlockModule::Customer :
        case FWFTextBlockModule::ReleasedProduct :
            selectedDetailsTab = 1;
            break;

        case FWFTextBlockModule::Supplier :
            selectedDetailsTab = 2;
            break;

        case FWFTextBlockModule::Project :
            selectedDetailsTab = 4;
            break;

        default :
            selectedDetailsTab = 1;
    }
}

dataAreaId lastValueDataAreaId()
{
    return '';
}

private identifiername lastValueDesignName()
{
    return '';
}

private identifiername lastValueElementName()
{
    return this.name();
}

private UtilElementType lastValueType()
{
    return UtilElementType::Form;
}

private userId lastValueUserId()
{
    return curuserid();
}

public container pack()
{
    return [#CurrentVersion,#CurrentList];
}

public boolean unpack(container packedClass)
{
    Integer     version     = conpeek(packedClass,1);

    switch (version)
    {
        case #CurrentVersion:
            [version,#CurrentList] = packedClass;
            break;
        default:
            return false;
    }

    return true;
}

public void updateDesign(InventDimFormDesignUpdate mode)
{
    if (mode == InventDimFormDesignUpdate::Init)
    {
        this.initDetailsTabFromModule();
        DetailsTab.tab(selectedDetailsTab);
    }

    this.showFields();

    if (HTML)
    {
        HTML.parmHtml(FWFTextBlockLanguage.htmlText());
    }

    TextGroup.allowEdit(FWFTextBlockTable.RecId);
}

void showFields()
{
    switch (FWFTextBlockTable.Module)
    {
        case FWFTextBlockModule::Customer :
            PrintOnPurchFormletters.visible(true);
            PrintOnSalesFormletters.visible(true);
            PrintOnProductionReports.visible(false);
            RelatedOrders.visible(false);
            PrintOnProjectReports.visible(false);
            break;

        case FWFTextBlockModule::Supplier :
            PrintOnPurchFormletters.visible(true);
            PrintOnSalesFormletters.visible(false);
            PrintOnProductionReports.visible(false);
            RelatedOrders.visible(false);
            PrintOnProjectReports.visible(false);
            break;

        case FWFTextBlockModule::Project :
            PrintOnPurchFormletters.visible(false);
            PrintOnSalesFormletters.visible(true);
            PrintOnProductionReports.visible(false);
            RelatedOrders.visible(false);
            PrintOnProjectReports.visible(true);
            break;

        case FWFTextBlockModule::ReleasedProduct :
            PrintOnPurchFormletters.visible(true);
            PrintOnSalesFormletters.visible(true);
            PrintOnProductionReports.visible(true);
            RelatedOrders.visible(true);
            PrintOnProjectReports.visible(true);
            break;

        default :
            PrintOnPurchFormletters.visible(true);
            PrintOnSalesFormletters.visible(true);
            PrintOnProductionReports.visible(true);
            RelatedOrders.visible(true);
            PrintOnProjectReports.visible(true);
    }
}

public void init()
{
    super();
}

public int active()
{
    int ret;

    ret = super();

    FWFTextBlockTable_ds.object(fieldNum(FWFTextBlockTable, module)).enabled(module || FWFTextBlockTable.RecId ? false : true);

    return ret;
}

public void initValue()
{
    super();

    if (module)
    {
        FWFTextBlockTable.Module = module;
    }
}

public void write()
{
    FWFTextBlockTable.SetupRefRecId = FWFTextBlockTableParm.RecId;

    super();
}

public void initValue()
{
    FWFTextBlockLanguage    localTextBlockLanguage;

    super();

    localTextBlockLanguage = FWFTextBlockLanguage::find(FWFTextBlockLanguage.TextBlockRecId, infolog.language());

    if (! localTextBlockLanguage)
    {
        FWFTextBlockLanguage.LanguageId = infolog.language();
        FWFTextBlockLanguage.write();
    }
}

public void write()
{
    super();

    element.updateDesign(InventDimFormDesignUpdate::Active);
}

public int active()
{
    int ret;

    ret = super();

    element.updateDesign(InventDimFormDesignUpdate::Active);

    return ret;
}

/// <summary>
///
/// </summary>
public void clicked()
{
    super();

    FormRun formRun;
    Args args = new Args();

    args.caller(this);
    args.name(formstr(FWFTextBlockTableHTML));
    args.record(FWFTextBlockLanguage);

    // Initialize editor form, run and wait
    formRun = ClassFactory.formRunClass(args);
    formRun.init();
    formRun.run();
    formRun.wait();

    // Refresh SysEmailSystemMessage datasource
    FWFTextBlockLanguage_ds.research(true);
}

public void pageActivated()
{
    element.updateDesign(InventDimFormDesignUpdate::Active);

    super();
}
